/* ─── Pulsing dot ─── */
function PulseDot({ color = COLORS.emerald, size = 10, delay = 0 }) {
  return (
    <span style={{
      display: "inline-block", width: size, height: size, borderRadius: "50%", background: color,
      animation: `pulse 2.4s ease-in-out ${delay}s infinite`, flexShrink: 0,
    }} />
  );
}

/* ─── Ecosystem card ─── */
function EcoCard({ icon: Icon, title, desc, delay, link, onNav }) {
  const [hovered, setHovered] = useState(false);
  const [ref, visible] = useInView(0.15);
  return (
    <div ref={ref}
      onMouseEnter={() => setHovered(true)} onMouseLeave={() => setHovered(false)}
      onClick={() => link && onNav && onNav(link)}
      style={{
        background: hovered
          ? `linear-gradient(165deg, ${COLORS.navy}, ${COLORS.deepTeal})`
          : "rgba(255,255,255,.75)",
        backdropFilter: "blur(16px)", WebkitBackdropFilter: "blur(16px)",
        borderRadius: 28, padding: "clamp(32px, 4vw, 48px) clamp(24px, 3vw, 36px)", cursor: "pointer",
        border: hovered ? `1px solid rgba(255,255,255,.1)` : "1px solid rgba(255,255,255,.6)",
        boxShadow: hovered ? `0 24px 64px rgba(8,69,94,.2)` : "0 4px 24px rgba(8,69,94,.06)",
        transition: "all 0.5s cubic-bezier(.16,1,.3,1)",
        opacity: visible ? 1 : 0, transform: visible ? `translateY(0)${hovered ? " translateY(-8px)" : ""}` : "translateY(40px)",
        transitionDelay: `${delay}s`,
        display: "flex", flexDirection: "column", flex: 1, minWidth: 260,
        textAlign: "left",
      }}
    >
      <div style={{
        width: 48, height: 48, borderRadius: 14, marginBottom: 28,
        background: hovered ? "rgba(255,255,255,.12)" : `${COLORS.teal}08`,
        border: hovered ? "1px solid rgba(255,255,255,.15)" : `1.5px solid ${COLORS.teal}20`,
        display: "flex", alignItems: "center", justifyContent: "center",
        transition: "all 0.4s",
      }}>
        <Icon size={22} color={hovered ? COLORS.emerald : COLORS.teal} strokeWidth={1.6} style={{ transition: "color 0.4s" }} />
      </div>
      <h3 style={{
        fontSize: "clamp(20px, 2vw, 24px)", fontWeight: 800, color: hovered ? "white" : COLORS.navy,
        margin: "0 0 12px 0", fontFamily: "'DM Sans', sans-serif", transition: "color 0.4s", letterSpacing: -0.5,
      }}>{title}</h3>
      <p style={{
        fontSize: 15, lineHeight: 1.7, color: hovered ? "rgba(255,255,255,.7)" : "#5a7a88",
        margin: 0, fontFamily: "'DM Sans', sans-serif", transition: "color 0.4s", flex: 1,
      }}>{desc}</p>
      <div style={{
        marginTop: 28, paddingTop: 20, borderTop: hovered ? "1px solid rgba(255,255,255,.1)" : `1px solid rgba(2,98,120,.06)`,
        display: "flex", alignItems: "center", justifyContent: "space-between",
        transition: "border-color 0.4s",
      }}>
        <span style={{
          fontSize: 14, fontWeight: 600, color: hovered ? COLORS.emerald : COLORS.teal,
          fontFamily: "'DM Sans', sans-serif", transition: "color 0.4s",
        }}>Learn More</span>
        <div style={{
          width: 32, height: 32, borderRadius: 10,
          background: hovered ? `${COLORS.emerald}20` : `${COLORS.teal}08`,
          display: "flex", alignItems: "center", justifyContent: "center",
          transition: "all 0.4s",
          transform: hovered ? "translateX(4px)" : "translateX(0)",
        }}>
          <ChevronRight size={16} color={hovered ? COLORS.emerald : COLORS.teal} strokeWidth={2} style={{ transition: "color 0.4s" }} />
        </div>
      </div>
    </div>
  );
}

