/* ─── Demo Modal ─── */
function DemoModal({ open, onClose }) {
  const [step, setStep] = useState("form");
  const [form, setForm] = useState({ name: "", email: "", phone: "", company: "" });
  const calRef = useRef(null);

  useEffect(() => {
    document.body.style.overflow = open ? "hidden" : "";
    if (!open) { setStep("form"); setForm({ name: "", email: "", phone: "", company: "" }); }
    return () => { document.body.style.overflow = ""; };
  }, [open]);

  useEffect(() => {
    if (step === "calendly" && calRef.current) {
      calRef.current.innerHTML = "";
      const s = document.createElement("script");
      s.src = "https://assets.calendly.com/assets/external/widget.js";
      s.async = true;
      document.body.appendChild(s);
      s.onload = () => {
        if (window.Calendly && calRef.current) {
          window.Calendly.initInlineWidget({
            url: "https://calendly.com/miguel-johns/milton-discovery-call?hide_gdpr_banner=1&primary_color=027b5e",
            parentElement: calRef.current,
          });
        }
      };
    }
  }, [step]);

  if (!open) return null;

  const valid = form.name && form.email && form.phone && form.company;

  return (
    <div style={{
      position: "fixed", inset: 0, zIndex: 200,
      display: "flex", alignItems: "center", justifyContent: "center",
      padding: 20,
    }}
      onClick={onClose}
    >
      {/* Backdrop */}
      <div style={{ position: "absolute", inset: 0, background: "rgba(8,69,94,.5)", backdropFilter: "blur(8px)", WebkitBackdropFilter: "blur(8px)" }} />

      {/* Modal */}
      <div
        onClick={e => e.stopPropagation()}
        style={{
          position: "relative", width: "100%",
          maxWidth: step === "form" ? 480 : 700,
          maxHeight: step === "form" ? "90vh" : "95vh",
          height: step === "calendly" ? "min(95vh, 850px)" : "auto",
          borderRadius: 28, background: "white",
          boxShadow: "0 32px 80px rgba(8,69,94,.2)",
          overflow: "hidden",
          display: "flex", flexDirection: "column",
          transition: "max-width 0.4s cubic-bezier(.16,1,.3,1), max-height 0.4s cubic-bezier(.16,1,.3,1)",
        }}
      >
        {/* Header */}
        <div style={{ padding: "24px 28px 0", display: "flex", justifyContent: "space-between", alignItems: "center" }}>
          <div style={{ display: "flex", alignItems: "center", gap: 10 }}>
            <div style={{ width: 32, height: 32, borderRadius: 10, overflow: "hidden" }}>
              <img src={MILTON_LOGO} alt="Milton" style={{ width: 32, height: 32, borderRadius: 10, objectFit: "cover" }} />
            </div>
            <span style={{ fontSize: 16, fontWeight: 700, color: COLORS.navy, fontFamily: "'DM Sans', sans-serif" }}>
              {step === "form" ? "Request a Demo" : "Book Your Call"}
            </span>
          </div>
          <button onClick={onClose} style={{
            width: 32, height: 32, borderRadius: 10, border: "none",
            background: "rgba(2,98,120,.04)", cursor: "pointer",
            display: "flex", alignItems: "center", justifyContent: "center",
          }}>
            <X size={16} color="#5a7a88" strokeWidth={2} />
          </button>
        </div>

        {step === "form" ? (
          <div style={{ padding: "24px 28px 28px", overflowY: "auto" }}>
            <p style={{ fontSize: 14, color: "#5a7a88", fontFamily: "'DM Sans', sans-serif", marginBottom: 28, lineHeight: 1.5 }}>
              Tell us a bit about yourself and we'll set up a 30-minute walkthrough of Milton.
            </p>
            <div style={{ display: "flex", flexDirection: "column", gap: 16 }}>
              {[
                { key: "name", label: "Full Name", placeholder: "Jane Smith", type: "text" },
                { key: "email", label: "Work Email", placeholder: "jane@yourgym.com", type: "email" },
                { key: "phone", label: "Phone Number", placeholder: "(555) 123-4567", type: "tel" },
                { key: "company", label: "Company / Gym Name", placeholder: "Peak Performance Gym", type: "text" },
              ].map(({ key, label, placeholder, type }) => (
                <div key={key}>
                  <label style={{ fontSize: 13, fontWeight: 600, color: COLORS.navy, fontFamily: "'DM Sans', sans-serif", display: "block", marginBottom: 6 }}>{label}</label>
                  <input
                    type={type}
                    placeholder={placeholder}
                    value={form[key]}
                    onChange={e => setForm({ ...form, [key]: e.target.value })}
                    style={{
                      width: "100%", padding: "14px 16px", borderRadius: 12,
                      border: "1.5px solid rgba(2,98,120,.1)", background: "#fafcfd",
                      fontSize: 15, fontFamily: "'DM Sans', sans-serif", color: COLORS.navy,
                      outline: "none", transition: "border-color 0.2s",
                    }}
                    onFocus={e => e.target.style.borderColor = COLORS.teal}
                    onBlur={e => e.target.style.borderColor = "rgba(2,98,120,.1)"}
                  />
                </div>
              ))}
            </div>
            <button
              onClick={() => { if (valid) setStep("calendly"); }}
              style={{
                width: "100%", marginTop: 24, padding: "16px", borderRadius: 14, border: "none",
                background: valid ? `linear-gradient(135deg, ${COLORS.navy}, ${COLORS.deepTeal})` : "rgba(2,98,120,.08)",
                color: valid ? "white" : "#9ab5c0",
                fontSize: 16, fontWeight: 700, cursor: valid ? "pointer" : "default",
                fontFamily: "'DM Sans', sans-serif",
                boxShadow: valid ? `0 8px 32px rgba(8,69,94,.2)` : "none",
                transition: "all 0.3s",
              }}
            >
              Continue to Booking
            </button>
          </div>
        ) : (
          <div style={{ flex: 1, overflowY: "auto", padding: "16px 28px 28px", minHeight: 0 }}>
            <div style={{
              padding: "12px 16px", borderRadius: 12, background: `${COLORS.emerald}08`,
              border: `1px solid ${COLORS.emerald}18`, marginBottom: 16,
              display: "flex", alignItems: "center", gap: 10,
            }}>
              <Check size={16} color={COLORS.emerald} strokeWidth={2.5} />
              <span style={{ fontSize: 14, fontWeight: 600, color: COLORS.teal, fontFamily: "'DM Sans', sans-serif" }}>
                Thanks, {form.name.split(" ")[0]}! Now pick a time that works.
              </span>
            </div>
            <div
              ref={calRef}
              style={{ height: 700, borderRadius: 16, overflow: "hidden" }}
            />
          </div>
        )}
      </div>
    </div>
  );
}

